export const sendEmail = emailData => {
  const params: AWS.SES.SendEmailRequest = {
    Source: emailData.senderEmail,
    Destination: {
      ToAddresses: emailData.recipientEmail,
    },
    Message: {
      Body: emailData.body,
      Subject: emailData.subject,
    },
  };
  return AWS_SES.sendEmail(params).promise();



