version: '3.8'
services:
  app:
    container_name: app
    restart: always
    build: .
    command: npm run start
    volumes:
      - .:/usr/app
      - /usr/app/node_modules
    ports:
      - 8088:8088
    depends_on:
      - mongo
      - mysql
      - redis
  mongo:
    container_name: mongo
    image: mongo
    restart: always
    volumes:
      - $HOME/docker/volumes/mongo:/data/db
    ports:
      - 27017:27017
  mysql:
    container_name: mysql
    image: biarms/mysql:5.7.30
    restart: always
    environment:
      - MYSQL_ROOT_PASSWORD=password
    ports:
      - 3306:3306
  redis:
    image: redis
    ports:
      - '6379:6379'



FROM node:18.19.1 AS build

WORKDIR /app

COPY package*.json ./

RUN npm install

COPY . .

RUN npm run build


EXPOSE 8080

# # Start server in dev mode (nodemon) or prod mode (node)
CMD ["npm", "run", "start"]







import { config } from './src/utils/config.utils';



# Builds the images required for the application
build:
	docker compose build --no-cache

# rebuild images
rebuild:
	docker compose up -d --build

# Creates containers, networks, volumes, etc. and start the containers
run:
	docker compose up -d

# Start the stopped containers
start:
	docker compose start

# Restart all containers
restart:
	docker compose restart

# Stop the running containers
stop:
	docker compose stop

# Stop and remove containers, networks, and non-persistent volumes
down:
	docker compose down



