{
  "name": "ramfin-tech-backend",
  "version": "0.0.0",
  "description": "ramfin-tech-backend application for upload and viewing the bank statements",
  "author": "",
  "license": "ISC",
  "scripts": {
    "migration:run": "ts-node -r tsconfig-paths/register ./node_modules/typeorm/cli.js migration:run -d src/utils/typeorm-migration.ts",
    "migration:revert": "ts-node -r tsconfig-paths/register ./node_modules/typeorm/cli.js migration:revert -d src/utils/typeorm-migration.ts",
    "start": "npm run build && npm run migration:run && cross-env node dist/server.js",
    "dev": "cross-env NODE_ENV=development nodemon",
    "consumer:start": "npm run build && cross-env node dist/consumer.js",
    "build": "swc src -d dist --source-maps --copy-files",
    "build:tsc": "tsc && tsc-alias",
    "test": "jest --forceExit --detectOpenHandles",
    "lint": "eslint --ignore-path .gitignore --ext .ts src/",
    "lint:fix": "npm run lint -- --fix",
    "deploy:prod": "npm run build && npm run migration:run && pm2 start ecosystem.config.js --only prod",
    "deploy:dev": "pm2 start ecosystem.config.js --only dev"
  },
